#include <iostream>
#include <vector>
#include <algorithm>

// The problematic reverseArray function
void reverseArray(int* arr, int size) {
    for (int i = 0; i <= (size - 1) / 2; ++i) {
        int temp = arr[i];
        arr[i] = arr[size - 1 - i];
        arr[size - 1 - i] = temp;
    }
}

void printArray(const std::vector<int>& arr) {
    for (size_t i = 0; i < arr.size(); ++i) {
        std::cout << arr[i] << (i == arr.size() - 1 ? "" : " ");
    }
    std::cout << std::endl;
}

int main() {
    std::vector<int> arr1 = {1, 2, 3, 4, 5};
    reverseArray(arr1.data(), arr1.size());
    printArray(arr1);

    std::vector<int> arr2 = {10, 20, 30, 40};
    reverseArray(arr2.data(), arr2.size());
    printArray(arr2);

    std::vector<int> arr3 = {100};
    reverseArray(arr3.data(), arr3.size());
    printArray(arr3);

    std::vector<int> arr4;
    // This call is expected to crash for arr4 (empty array)
    reverseArray(arr4.data(), arr4.size()); 
    // The program might not reach here or might print garbage depending on UB
    printArray(arr4);

    return 0;
}
